Bash(cd "E:\\Websites\\droptaxi" && node -e "
const fs = require\('fs'\);
const raw = fs.readFileSync\('C:/Users/karth/.claude/projects/E--Websites-droptaxi/028e9189-1eae-4565-9c5f-9fe869a4302e/tool-results/mcp-dataforseo-keyword_search_volume-1773300419928.txt', 'utf8'\);
const parsed = JSON.parse\(raw\);
const text = parsed[0].text;
const data = JSON.parse\(text\);
const keywords = data.keywords || [];
keywords.sort\(\(a,b\) => \(b.search_volume||0\) - \(a.search_volume||0\)\);

// Full dataset with page mapping
const pageMap = require\('./reports/all-page-keywords.json'\);
// Reverse map: keyword -> slug
const kwToSlug = {};
for \(const [cat, map] of Object.entries\(pageMap\)\) {
  if \(cat === 'allKeywords'\) continue;
  for \(const [slug, kw] of Object.entries\(map\)\) {
    kwToSlug[kw] = slug;
  }
}

const result = keywords.map\(k => \({
  keyword: k.keyword,
  slug: kwToSlug[k.keyword] || 'UNMAPPED',
  search_volume: k.search_volume || 0,
  cpc: k.cpc || 0,
  competition: k.competition || 'NONE',
  competition_index: k.competition_index || 0,
}\)\);

fs.writeFileSync\('./reports/serp-analysis-all-keywords.json', JSON.stringify\({
  totalKeywords: result.length,
  withVolume: result.filter\(r => r.search_volume > 0\).length,
  zeroVolume: result.filter\(r => r.search_volume === 0\).length,
  totalMonthlySearches: result.reduce\(\(sum, r\) => sum + r.search_volume, 0\),
  keywords: result
}, null, 2\)\);
console.log\('Saved. Total:', result.length, '| With volume:', result.filter\(r => r.search_volume > 0\).length, '| Zero:', result.filter\(r => r.search_volume === 0\).length\);
console.log\('Total monthly search volume:', result.reduce\(\(sum, r\) => sum + r.search_volume, 0\)\);
" 2>&1)

